INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (1, 2, "vo_minigame_1013_icon_2_002_001", "vo_minigame_1013_icon_1_002_001", "訓練はまだ\nここからですわ", 1000, "調子が上がって\nきたなっ", 2, 2, 3000);
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (2, 2, "vo_minigame_1013_icon_2_003_001", "vo_minigame_1013_icon_1_003_001", "クスクス、悪くない\n流れですわね", 5000, "ほらほら、\nまだいけるだろ？", 2, 2, 3000);
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (3, 3, "vo_minigame_1013_icon_2_004_001", "vo_minigame_1013_icon_1_004_001", "すばらしい\n記録ですわ", 10000, "へへっ、おまえら\nやるじゃねえか！", 2, 2, 3000);
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (4, 3, "vo_minigame_1013_icon_2_005_001", "vo_minigame_1013_icon_1_005_001", "乗りに乗って\nいますわね", 10000, "あたしたちはまだ\n止まらねえぜ！", 2, 3, 3000);
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (5, 3, "vo_minigame_1013_icon_2_005_002", "vo_minigame_1013_icon_1_005_002", "まだまだ行きます\nついてきなさい", 10000, "見てろよ！\nマコト班の快進撃だ！", 2, 3, 3000);
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (6, 3, "vo_minigame_1013_icon_2_005_003", "vo_minigame_1013_icon_1_005_003", "エリコ班の\n本領発揮ですわ！", 10000, "うおぉぉっ！\n絶好調だぜ！", 2, 3, 3000);
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (7, 3, "vo_minigame_1013_icon_2_006_001", "vo_minigame_1013_icon_1_006_001", "ここからは\n前人未到の領域です！", 0, "どこまで行けるか\n楽しみだなっ！", 2, 4, 3000);
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (8, 4, "vo_minigame_1013_icon_2_007_001", "vo_minigame_1013_icon_1_007_001", "厄介でしたわ…", 1, "まだ諦めんなよっ", 3, 5, 1000);
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (9, 4, "vo_minigame_1013_icon_2_007_002", "vo_minigame_1013_icon_1_007_002", "油断大敵です", 1, "冷やっとしたぜ…！", 3, 5, 1000);
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (10, 4, "vo_minigame_1013_icon_2_007_003", "vo_minigame_1013_icon_1_007_003", "忌々しいっ…", 1, "弱音を吐くなっ", 3, 5, 1000);
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (11, 3, "vo_minigame_1013_icon_2_008_001", "vo_minigame_1013_icon_1_008_001", "大所帯ですわね", 99, "マコト班集合！", 4, 6, 1500);
